{
  "title": "Understanding Cold Sensations and Fever Management",
  "description": "This course aims to educate individuals on the relationship between feeling cold, fever symptoms, and associated conditions. It will cover the importance of self-monitoring and when to seek medical attention.",
  "modules": [
    {
      "id": "module1",
      "title": "Introduction to Body Temperature Regulation",
      "description": "Explore how the body regulates temperature, the concept of fever, and why you might feel cold even when experiencing symptoms of illness."
    },
    {
      "id": "module2",
      "title": "Identifying Symptoms and Their Implications",
      "description": "Learn to recognize various symptoms associated with cold sensations and fever, including sneezing, and understand their potential causes."
    },
    {
      "id": "module3",
      "title": "Self-Monitoring Techniques",
      "description": "Understand the importance of monitoring your temperature and other symptoms, and learn effective techniques for accurate self-assessment."
    },
    {
      "id": "module4",
      "title": "When to Seek Medical Attention",
      "description": "Discuss guidelines for determining when to consult a healthcare professional based on your symptoms and duration of illness."
    }
  ]
}
